def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    m = len(t)
    if m == 0:
        return 1
    n = len(s)
    if n == 0:
        return 0

    dp = [0] * (m + 1)
    dp[0] = 1  # empty subsequence matches empty t

    for ch in s:
        # iterate backwards to avoid overwriting needed previous values
        for j in range(m, 0, -1):
            if ch == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
